import { useState } from 'react';
import './App.css';
import Home from './Components/Home';
import TrainersList from './Components/TrainersList';
import TrainerDetails from './Components/TrainerDetails';
import trainers from './TrainersMock';

function App() {
  const [selectedTrainerId, setSelectedTrainerId] = useState(trainers[0]?.id || null);

  const selectedTrainer = trainers.find((trainer) => trainer.id === selectedTrainerId) || trainers[0];

  return (
    <div className="app">
      <Home />
      <div className="content">
        <TrainersList trainers={trainers} selectedTrainerId={selectedTrainerId} onSelectTrainer={setSelectedTrainerId} />
        <TrainerDetails trainer={selectedTrainer} />
      </div>
    </div>
  );
}

export default App;
